    {
      "id": "PQ-01",
      "question": "培训课程费标准是多少？",
      "policy_doc": "05_training_expense.md",
      "clause": "第二条",
      "rule": "培训课程费按人次控制,每人每期不超过3500元"
    },
    {
      "id": "PQ-02",
      "question": "超标准报销的判定条件是什么？",
      "policy_doc": "01_expense_reimbursement_2025.md",
      "clause": "第十二条",
      "rule": "无专项审批时,报销金额不得超过对应制度标准的1.0倍"
    },
    {
      "id": "PQ-03",
      "question": "R004223是否属于超标准报销？",
      "policy_doc": "05_training_expense.md",
