    "R004223的完整记录和审批信息",
    "所有金额超过3500元的培训费记录及金额对比",
    "每条异常记录对应的政策条款引用",
    "专项审批标识核实"
  ],
  "execution_steps": [
    {"step": 1, "action": "audit-query-planner", "description": "规划审计范围和方法", "artifact": "work/audit_plan.json", "status": "completed"},
    {"step": 2, "action": "policy-version-check", "description": "确认适用的政策版本和条款", "trigger": "training_fee涉及培训费管理办法,需确认2025版有效", "artifact": "work/policy_check.json"},
    {"step": 3, "action": "batch-expense-analysis", "description": "批量分析培训费数据,检测所有超标准记录", "trigger": "需要聚合筛选培训费 > 3500", "artifact": "work/batch_analysis.json"},
    {"step": 4, "action": "check R004223 detail and approvals", "description": "核实R004223的详细信息、审批层级和专项审批状态", "artifact": "work/R004223_detail.json"},
    {"step": 5, "action": "evidence-coverage-check", "description": "检查证据覆盖度和一致性", "artifact": "work/evidence_matrix.json"},
    {"step": 6, "action": "false-positive-review", "description": "独立复核是否有豁免或例外", "trigger": "有异常发现时", "artifact": "work/false_positive_review.json"},
    {"step": 7, "action": "audit-report", "description": "生成审计报告", "artifact": "work/audit_report.json"},
    {"step": 8, "action": "result-validator", "description": "验证结果格式和一致性", "artifact": "work/validation_report.json"},
    {"step": 9, "action": "validate + submit", "description": "调用validate_audit_result和submit_audit_result", "artifact": "work/final_result.json"}
  ],
  "complexity": {
    "score": 2,
    "reasons": [
      "涉及阈值判断（3500元标准线）",
      "需要批处理聚合筛选（所有培训费 > 3500）",
      "单条规则单条政策",
      "无政策版本冲突"
    ]
  },
  "subagent_plan": {
    "required": false,
    "reason": "complexity=2但任务范围明确、规则单一、数据可通过直接查询获取,无需专业子智能体"
  },
  "stopping_conditions": [
    "所有培训费超过3500元的记录已被识别并核实",
    "每条异常记录有对应的政策条款引用",
    "evidence_matrix覆盖率达到100%",
    "validation_report状态为pass"
  ],
  "unresolved_items": ["需确认是否存在其他与R004223共享特征的超标准记录（如同一供应商、同一发票、同一部门D009的其他培训费）"]
}

